def count_calls(func):
    count = 0
    def wrapper(*args, **kwargs):
        nonlocal count
        count = count + 1
        print(f'第 {count} 次调用')
        return func(*args, **kwargs)
    return wrapper

@count_calls
def say_hi():
    print('hi')

say_hi()
say_hi()
